final:
module RefModule(
    input enable,
    input [1:0] in,
    output reg [3:0] out
);

always @(*)
    if (enable)
        case (in)
            2'b00: out = 4'b0001;
            2'b01: out = 4'b0010;
            2'b10: out = 4'b0100;
            2'b11: out = 4'b1000;
            default: out = 4'b0000;
        endcase
    else
        out = 4'b0000; // Output is 0 when not enabled

endmodule
